import{_ as i,c as o,o as r,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.2.5: Desktop Experience Optimization, New Font Option","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.2.5.md","filePath":"en/changelog/v1.2.5.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.2.5.md"};function s(l,t,d,h,p,u){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="v1-2-5-desktop-experience-optimization-new-font-option" tabindex="-1">v1.2.5: Desktop Experience Optimization, New Font Option <a class="header-anchor" href="#v1-2-5-desktop-experience-optimization-new-font-option" aria-label="Permalink to “v1.2.5: Desktop Experience Optimization, New Font Option”">​</a></h1><p><strong>Release Date</strong>: February 15, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update makes <strong>the desktop application more usable</strong>, fixes file opening issues, and adds new font and keyboard shortcuts.</p><hr><h2 id="bug-fix-opening-new-files-from-file-tree" tabindex="-1">Bug Fix: Opening New Files from File Tree <a class="header-anchor" href="#bug-fix-opening-new-files-from-file-tree" aria-label="Permalink to “Bug Fix: Opening New Files from File Tree”">​</a></h2><h3 id="the-previous-problem" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>In the desktop application, sometimes new files opened from the file tree couldn&#39;t be viewed properly.</p><h3 id="the-current-situation" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation" aria-label="Permalink to “The Current Situation”">​</a></h3><p>This issue has been fixed, and you can now smoothly open and switch between files.</p><hr><h2 id="new-feature-shift-tab-keyboard-shortcut" tabindex="-1">New Feature: Shift+Tab Keyboard Shortcut <a class="header-anchor" href="#new-feature-shift-tab-keyboard-shortcut" aria-label="Permalink to “New Feature: Shift+Tab Keyboard Shortcut”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added the <code>Shift+Tab</code> keyboard shortcut in the desktop application.</p><h3 id="where-to-use-it" tabindex="-1">Where to use it? <a class="header-anchor" href="#where-to-use-it" aria-label="Permalink to “Where to use it?”">​</a></h3><p><code>Shift+Tab</code> is typically used for <strong>reverse navigation</strong> (opposite of Tab), for example:</p><ul><li>Moving from current input box back to previous input box</li><li>Reversing through interactive elements</li></ul><hr><h2 id="new-feature-geistmono-nerd-font" tabindex="-1">New Feature: GeistMono Nerd Font <a class="header-anchor" href="#new-feature-geistmono-nerd-font" aria-label="Permalink to “New Feature: GeistMono Nerd Font”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added <strong>GeistMono Nerd Font</strong> to the desktop application&#39;s font options.</p><h3 id="what-is-geistmono" tabindex="-1">What is GeistMono? <a class="header-anchor" href="#what-is-geistmono" aria-label="Permalink to “What is GeistMono?”">​</a></h3><p>GeistMono is a modern, clean open-source monospace font, especially suitable for coding:</p><ul><li>Clear and readable</li><li>Supports special characters for multiple programming languages</li><li>Clean visual style</li></ul><h3 id="what-is-nerd-font" tabindex="-1">What is Nerd Font? <a class="header-anchor" href="#what-is-nerd-font" aria-label="Permalink to “What is Nerd Font?”">​</a></h3><p>Nerd Font is a version with <strong>many icons added</strong> to the original font, including:</p><ul><li>Git branch icons</li><li>Programming language icons</li><li>File type icons</li><li>And more</li></ul><p><strong>Simply put</strong>: Both beautiful and practical!</p><h3 id="how-to-switch-fonts" tabindex="-1">How to switch fonts? <a class="header-anchor" href="#how-to-switch-fonts" aria-label="Permalink to “How to switch fonts?”">​</a></h3><ol><li>Open the desktop application</li><li>Go to <strong>Settings</strong></li><li>Find <strong>Font Settings</strong></li><li>Select <strong>GeistMono Nerd Font</strong> from the monospace font options</li><li>Apply and enjoy the new font</li></ol><hr><h2 id="bug-fix-window-focus" tabindex="-1">Bug Fix: Window Focus <a class="header-anchor" href="#bug-fix-window-focus" aria-label="Permalink to “Bug Fix: Window Focus”">​</a></h2><h3 id="the-previous-problem-1" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem-1" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>After updates or restarts, the desktop application window might lose focus, requiring manual clicking to continue input.</p><h3 id="the-current-situation-1" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation-1" aria-label="Permalink to “The Current Situation”">​</a></h3><p>Window is now automatically focused after updates and restarts, so you can continue using it directly.</p><hr><h2 id="bug-fix-prompt-history-navigation" tabindex="-1">Bug Fix: Prompt History Navigation <a class="header-anchor" href="#bug-fix-prompt-history-navigation" aria-label="Permalink to “Bug Fix: Prompt History Navigation”">​</a></h2><h3 id="the-previous-problem-2" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem-2" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>When using up/down arrows to view prompt history, sometimes history would switch at arbitrary positions in the middle of the input box, providing poor user experience.</p><h3 id="the-current-situation-2" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation-2" aria-label="Permalink to “The Current Situation”">​</a></h3><p>Now history only switches at <strong>input boundaries</strong> (cursor at beginning or end), preventing accidental triggers in the middle.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Daily desktop user</td><td>✅ Upgrade</td></tr><tr><td>Want to try new font</td><td>✅ Upgrade</td></tr><tr><td>Encountered file opening issues</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next release</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',47),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-optional" tabindex="-1">Technical Details (Optional) <a class="header-anchor" href="#technical-details-optional" aria-label="Permalink to “Technical Details (Optional)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Ensure SQLite migration logs to stderr instead of stdout</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fixed issue with opening new files from file tree</li><li>Only navigate prompt history at input boundaries</li><li>Added Shift+Tab keyboard shortcut</li><li>Focus window after update and restart</li><li>Added GeistMono Nerd Font to available monospace font options</li></ul><h3 id="community-contributors" tabindex="-1">Community Contributors <a class="header-anchor" href="#community-contributors" aria-label="Permalink to “Community Contributors”">​</a></h3><p>Thanks to 7 community contributors:</p><ul><li>@brandon-julio-t: Added GeistMono Nerd font</li><li>@zeroneix: Fixed window focus issue</li><li>@dector: Added Ukrainian README translation</li><li>@neriousy: Added Shift+Tab shortcut</li><li>@nexxeln: Fixed prompt history navigation</li><li>@shanebishop1: Fixed file tree opening new files</li><li>@alexyaroshuk: Localized &quot;Free quota exceeded&quot; error</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const b=i(n,[["render",s]]);export{m as __pageData,b as default};
